mapper.select:
SELECT *
FROM tm_manual_consult_session session
WHERE (
  session.questioner_name = #{currentUserName}
  OR session.service_display_name = #{currentUserName}
  OR session.service_alias = #{currentUserName}
  OR session.transferred_from_name = #{currentUserName}
  OR EXISTS (
    SELECT 1
    FROM tm_manual_consult_participant participant
    WHERE participant.session_id = session.id
      AND participant.participant_name = #{currentUserName}
  )
)
ORDER BY COALESCE(session.last_message_at, session.created_at) DESC, session.id DESC

SELECT participant_key
FROM tm_manual_consult_participant
WHERE session_id = #{sessionId}
  AND participant_type = #{participantType}
ORDER BY id ASC

mapper.insert:
INSERT INTO tm_manual_consult_participant(session_id, participant_type, participant_key, participant_name)
SELECT #{sessionId}, #{participantType}, #{participantKey}, #{participantName}
WHERE NOT EXISTS (
  SELECT 1 FROM tm_manual_consult_participant
  WHERE session_id = #{sessionId} AND participant_type = #{participantType} AND participant_key = #{participantKey}
)
